updated as (
  update public.conciertos as target
  set
    fecha = source.fecha,
    sala = source.sala,
    ciudad = source.ciudad,
    grupo_id = source.grupo_id,
    festival = source.festival,
    fotos = source.fotos,
    entrada = source.entrada,
    descripcion = source.descripcion,
    cartel = source.cartel,
    cronica = source.cronica,
    videos = source.videos,
    videos_instagram = source.videos_instagram
  from source
  where target.id = source.id
  returning target.id
)
insert into public.conciertos (
  id,
  fecha,
  sala,
  ciudad,
  grupo_id,
  festival,
  fotos,
  entrada,
  descripcion,
  cartel,
  cronica,
  videos,
  videos_instagram
)
select
  source.id,
  source.fecha,
  source.sala,
  source.ciudad,
  source.grupo_id,
  source.festival,
  source.fotos,
  source.entrada,
  source.descripcion,
  source.cartel,
  source.cronica,
  source.videos,
  source.videos_instagram
from source
left join updated on updated.id = source.id
where updated.id is null
on conflict (id) do nothing;

select setval(
  pg_get_serial_sequence('public.conciertos', 'id'),
  coalesce((select max(id) from public.conciertos), 1),
  true
);

