  select '2024-07-26'::date as fecha, 'Bilbao Blues Festival'::text as sala, 'Bilbao'::text as ciudad, (select id from public.grupos where nombre = 'Southern Avenue' limit 1)::bigint as grupo_id, false::boolean as festival, false::boolean as fotos, null::text as entrada, null::text as descripcion, null::text as cartel, null::text as cronica, ARRAY['https://www.youtube.com/embed/_Rt4Xy3B8gI?si=MD9PrCRKcx77jH2P']::text[] as videos, ARRAY[]::text[] as videos_instagram
  union all
  select '2024-07-27'::date as fecha, 'Bilbao Blues Festival'::text as sala, 'Bilbao'::text as ciudad, (select id from public.grupos where nombre = 'The Fabulous Thunderbirds' limit 1)::bigint as grupo_id, false::boolean as festival, false::boolean as fotos, null::text as entrada, null::text as descripcion, null::text as cartel, null::text as cronica, ARRAY['https://www.youtube.com/embed/mHDfkq3bJPA?si=MhHOF1B2z3iJAGQc']::text[] as videos, ARRAY[]::text[] as videos_instagram
)
insert into public.conciertos (
  fecha,
  sala,
  ciudad,
  grupo_id,
  festival,
  fotos,
  entrada,
  descripcion,
  cartel,
  cronica,
  videos,
  videos_instagram
)
select
  source.fecha,
  source.sala,
  source.ciudad,
  source.grupo_id,
  source.festival,
  source.fotos,
  source.entrada,
  source.descripcion,
  source.cartel,
  source.cronica,
  source.videos,
  source.videos_instagram
from source
where not exists (
  select 1
  from public.conciertos existing
  where existing.fecha = source.fecha
    and coalesce(existing.sala, '') = coalesce(source.sala, '')
    and coalesce(existing.ciudad, '') = coalesce(source.ciudad, '')
    and coalesce(existing.grupo_id, 0) = coalesce(source.grupo_id, 0)
);

select setval(
  pg_get_serial_sequence('public.conciertos', 'id'),
  coalesce((select max(id) from public.conciertos), 1),
  true
);


commit;
